class Solution:
    def countDays(self, days: int, meetings: List[List[int]]) -> int:
        # Sort meetings by start time
        meetings.sort()
        merged = []
        for meet in meetings:
            if not merged:
                merged.append(meet)
            else:
                last = merged[-1]
                # Check if current meeting overlaps with the last merged meeting
                if meet[0] <= last[1]:
                    # Merge intervals
                    merged[-1] = [last[0], max(last[1], meet[1])]
                else:
                    merged.append(meet)

        # Calculate total days covered by meetings
        total_meeting_days = 0
        for start, end in merged:
            total_meeting_days += end - start + 1

        # Days available but no meetings = total days - total meeting days
        return days - total_meeting_days
